import { Component, h, Prop, Method } from '@stencil/core';

@Component({
  tag: 'wdpr-card-footer',
  styles: `:host { width: 100%; }`,
  shadow: true,
})
export class WdprCardFooter {
  @Prop() headTitle: string;
  @Prop() description: string;
  @Prop() linkText: string;
  @Prop() linkHref: string = '#';
  @Prop() linkPosition: 'top' | 'bottom' = 'bottom';
  @Prop() icon: string;
  @Prop() showMoreOptions: boolean = false;
  @Prop() variant: 'informational' | 'warning' | 'critical' | 'swap' | 'general' = 'general';
  @Prop() disabled: boolean = false;

  @Method()
  async setDisabledState(isDisabled: boolean) {
    this.disabled = isDisabled;
  }

  get iconVariantColor() {
    if (this.disabled) {
      return 'neutral';
    }

    switch (this.variant) {
      case 'warning':
        return 'warning';
      case 'critical':
        return 'error';
      case 'general':
        return 'secondary';
      default:
        return 'info';
    }
  }

  get iconName() {
    if (this.icon && this.variant === 'general') {
      return this.icon;
    }

    switch (this.variant) {
      case 'informational':
        return 'info';
      case 'warning':
        return 'alert';
      case 'critical':
        return 'alert-notification-1';
      case 'general':
        return this.icon || 'info';
      default:
        return 'info';
    }
  }

  private _renderLink() {
    if (this.linkText && this.linkHref) {
      return (
        <wdpr-text-link size="xxsmall" href={this.linkHref} disabled={this.disabled}>
          {this.linkText}
          <wdpr-icon-library slot="trailing-icon" icon="next-caret-2.0" size="xxsmall" decorative></wdpr-icon-library>
        </wdpr-text-link>
      );
    }

    return null;
  }

  render() {
    const footerBgClasses = this.disabled ? 'bg-surface-actionable-card-disabled' : 'bg-surface-default';
    const footerBorderTopClasses = 'border-t border-solid border-stroke-default';
    const footerTextClasses = this.disabled ? 'text-text-disabled' : 'text-text-heading';
    const footerOpacityClasses = this.disabled ? 'opacity-200' : '';

    return (
      <div id='card-footer' class={`${footerBgClasses} ${footerBorderTopClasses} box-border flex p-200 w-full`}>
        {this.variant === 'swap' ? <div class='flex justify-center items-center w-full'><slot /></div> :
          <div class='flex w-full gap-3 items-start'>
            <wdpr-icon
              class={footerOpacityClasses}
              variant={this.iconVariantColor}
              icon={this.iconName}
              size="xxsmall"
              background="circle"
            ></wdpr-icon>

            <div class="flex flex-col grow items-start justify-center h-full">
              {this.linkPosition === 'top' && this._renderLink()}
              <div id='card-footer-title' class={`${footerTextClasses} font-bold component-small w-full`}>
                {this.headTitle}
              </div>
              <div id='card-footer-description' class={`${footerTextClasses} min-w-full body-small`}>
                {this.description}
              </div>
              {this.linkPosition === 'bottom' && this._renderLink()}
            </div>

            <div class='flex items-center justify-center min-w-400'>
              <slot name="actions" />
            </div>
          </div>
        }
      </div>
    );
  }
}
